/**
 * @summary Send a transactional email
 */
export const getSendTransactionalUrl = () => {
  return `/api/transactional/send`;
};

export const sendTransactional = async (
  sendTransactionalInput: SendTransactionalInput,
  options?: RequestInit,
): Promise<MessageResult> => {
  return customFetch<MessageResult>(getSendTransactionalUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(sendTransactionalInput),
  });
};

export const getSendTransactionalMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof sendTransactional>>,
    TError,
    { data: BodyType<SendTransactionalInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof sendTransactional>>,
  TError,
  { data: BodyType<SendTransactionalInput> },
  TContext
> => {
  const mutationKey = ["sendTransactional"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof sendTransactional>>,
    { data: BodyType<SendTransactionalInput> }
  > = (props) => {
    const { data } = props ?? {};

    return sendTransactional(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SendTransactionalMutationResult = NonNullable<
  Awaited<ReturnType<typeof sendTransactional>>
>;
export type SendTransactionalMutationBody = BodyType<SendTransactionalInput>;
export type SendTransactionalMutationError = ErrorType<unknown>;

